class Solution:
    def lengthLongestPath(self, input: str) -> int:
        stack, ans = [0], 0
        for line in input.split('\n'):
            depth = line.count('\t')
            name = line[depth:]
            length = stack[depth] + len(name) + (1 if depth else 0)
            if depth + 1 == len(stack): stack.append(length)
            else: stack[depth + 1] = length
            if '.' in name:
                ans = max(ans, length)
        return ans

